// Generated by GitHub Copilot
const ApiError = require('../utils/ApiError')
const Member = require('../models/Member')
const Contribution = require('../models/Contribution')
const Loan = require('../models/Loan')
const { toPublicUser } = require('./authService')
const { logAudit } = require('../utils/auditLogger')
const { createNotification } = require('../utils/notificationHelper')

/** Shape a Member document into a safe, API-friendly object (no password). */
function toPublicMember(member) {
  return toPublicUser(member, 'member')
}

/**
 * Escape user-supplied text before using it inside a RegExp so a search term
 * cannot inject regex syntax (prevents ReDoS / unexpected matches).
 * @param {string} value
 * @returns {string}
 */
function escapeRegex(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

/**
 * Create a new member. Rejects duplicate email/mobile with a clear 409 before
 * relying on the unique index as the ultimate safeguard.
 * @param {{ name: string, mobile: string, email: string, password: string, status?: string, joiningDate?: string }} data
 * @returns {Promise<object>} Public member.
 */
async function createMember({ name, mobile, email, password, status, joiningDate }, meta = {}) {
  const normalizedEmail = email.toLowerCase()
  const existing = await Member.findOne({
    $or: [{ email: normalizedEmail }, { mobile }],
    isDeleted: false,
  })
  if (existing) {
    const field = existing.email === normalizedEmail ? 'email' : 'mobile'
    throw new ApiError(409, `A member with this ${field} already exists`, [
      { field, message: `This ${field} is already registered` },
    ])
  }

  const member = await Member.create({
    name,
    mobile,
    email: normalizedEmail,
    password,
    ...(status ? { status } : {}),
    ...(joiningDate ? { joiningDate } : {}),
  })

  logAudit(meta, {
    action: 'MEMBER_CREATED',
    entity: 'Member',
    entityId: member._id,
    description: `Member ${member.name} created`,
  })

  return toPublicMember(member)
}

/**
 * List members with optional search, status filter and pagination.
 * @param {{ search?: string, status?: string, page?: number, limit?: number }} query
 * @returns {Promise<{ members: object[], pagination: object }>}
 */
async function listMembers({ search, status, page = 1, limit = 10 } = {}) {
  const filter = {}

  if (status) filter.status = status

  if (search && search.trim()) {
    const term = new RegExp(escapeRegex(search.trim()), 'i')
    filter.$or = [{ name: term }, { email: term }, { mobile: term }]
  }

  const currentPage = Math.max(1, Number(page) || 1)
  const perPage = Math.min(100, Math.max(1, Number(limit) || 10))
  const skip = (currentPage - 1) * perPage

  filter.isDeleted = false

  const [docs, total] = await Promise.all([
    Member.find(filter).sort({ createdAt: -1 }).skip(skip).limit(perPage),
    Member.countDocuments(filter),
  ])

  const memberIds = docs.map((d) => d._id)

  const [contributionTotals, loanTotals] = await Promise.all([
    Contribution.aggregate([
      { $match: { memberId: { $in: memberIds }, status: 'paid' } },
      { $group: { _id: '$memberId', total: { $sum: '$amount' } } },
    ]),
    Loan.aggregate([
      { $match: { memberId: { $in: memberIds }, status: 'active' } },
      { $group: { _id: '$memberId', total: { $sum: '$remaining' } } },
    ]),
  ])

  const contributionMap = new Map(contributionTotals.map((r) => [String(r._id), r.total]))
  const loanMap = new Map(loanTotals.map((r) => [String(r._id), r.total]))

  return {
    members: docs.map((doc) => {
      const publicMember = toPublicMember(doc)
      const id = String(doc._id)
      return {
        ...publicMember,
        totalContribution: contributionMap.get(id) || 0,
        activeLoan: loanMap.get(id) || 0,
      }
    }),
    pagination: {
      page: currentPage,
      limit: perPage,
      total,
      totalPages: Math.ceil(total / perPage) || 1,
    },
  }
}

/**
 * Fetch a single member by id.
 * @param {string} id
 * @returns {Promise<object>} Public member.
 */
async function getMemberById(id) {
  const member = await Member.findOne({ _id: id, isDeleted: false })
  if (!member) throw new ApiError(404, 'Member not found')
  return toPublicMember(member)
}

/**
 * Update a member's editable fields. Uniqueness of email/mobile is enforced
 * against other members. Passing `password` re-hashes it via the save hook.
 * @param {string} id
 * @param {object} data
 * @returns {Promise<object>} Public member.
 */
async function updateMember(id, data, meta = {}) {
  const member = await Member.findOne({ _id: id, isDeleted: false })
  if (!member) throw new ApiError(404, 'Member not found')

  const { name, mobile, email, password, status, joiningDate } = data

  if (email && email.toLowerCase() !== member.email) {
    const normalizedEmail = email.toLowerCase()
    const clash = await Member.findOne({ email: normalizedEmail, _id: { $ne: id } })
    if (clash) {
      throw new ApiError(409, 'A member with this email already exists', [
        { field: 'email', message: 'This email is already registered' },
      ])
    }
    member.email = normalizedEmail
  }

  if (mobile && mobile !== member.mobile) {
    const clash = await Member.findOne({ mobile, _id: { $ne: id } })
    if (clash) {
      throw new ApiError(409, 'A member with this mobile already exists', [
        { field: 'mobile', message: 'This mobile is already registered' },
      ])
    }
    member.mobile = mobile
  }

  if (name !== undefined) member.name = name
  if (status !== undefined) member.status = status
  if (joiningDate !== undefined) member.joiningDate = joiningDate
  if (password) member.password = password // pre-save hook re-hashes

  await member.save()

  logAudit(meta, {
    action: 'MEMBER_UPDATED',
    entity: 'Member',
    entityId: member._id,
    description: `Member ${member.name} updated`,
  })

  return toPublicMember(member)
}

/**
 * Activate or deactivate a member.
 * @param {string} id
 * @param {'Active'|'Inactive'} status
 * @returns {Promise<object>} Public member.
 */
async function setMemberStatus(id, status, meta = {}) {
  const member = await Member.findOne({ _id: id, isDeleted: false })
  if (!member) throw new ApiError(404, 'Member not found')
  member.status = status
  await member.save()

  logAudit(meta, {
    action: 'MEMBER_STATUS_CHANGED',
    entity: 'Member',
    entityId: member._id,
    description: `Member ${member.name} status changed to ${status}`,
  })

  createNotification({
    recipientId: member._id,
    recipientRole: 'member',
    title: 'Account status updated',
    message: `Your account has been ${status === 'Active' ? 'activated' : 'deactivated'}. Contact the admin for more details.`,
    type: status === 'Active' ? 'success' : 'warning',
    relatedEntity: 'Member',
    relatedEntityId: member._id,
  })

  return toPublicMember(member)
}

module.exports = {
  createMember,
  listMembers,
  getMemberById,
  updateMember,
  setMemberStatus,
}
